-- =====================================================================
-- X) EXTENDED TOUR SCHEDULES (3 Months, ~4-5 deps/month per tour)
-- We simulate 4 schedules per month for up to 3-4 months into the future.
-- By multiplying mo.idx (month) and wk.idx (week of month) mapped to t.id offset, 
-- we get discrete, non-overlapping weekly/monthly departures.
-- =====================================================================
INSERT IGNORE INTO tour_schedules (
    schedule_code, tour_id, departure_at, return_at,
    capacity_total, booked_seats, adult_price, child_price, status
)
SELECT 
    CONCAT('SCH_EXT_', t.id, '_M', mo.idx, 'W', wk.idx),
    t.id,
    -- (mo.idx * 30 days) + (wk.idx * 7 days) + pseudo random day offset
    DATE_ADD(CURDATE(), INTERVAL ((mo.idx * 30) + (wk.idx * 7) + (t.id % 5) + 3) DAY),
    DATE_ADD(CURDATE(), INTERVAL ((mo.idx * 30) + (wk.idx * 7) + (t.id % 5) + 3 + t.duration_days) DAY),
    30,
    MOD(t.id + mo.idx + wk.idx, 15),
    t.base_price,
    ROUND(t.base_price * 0.75),
    'open'
FROM tours t
CROSS JOIN (
    -- 3 months
    SELECT 0 AS idx UNION ALL SELECT 1 UNION ALL SELECT 2
) mo
CROSS JOIN (
    -- 4 weeks (schedules) per month
    SELECT 0 AS idx UNION ALL SELECT 1 UNION ALL SELECT 2 UNION ALL SELECT 3
) wk
WHERE t.deleted_at IS NULL;


DELETE FROM tour_departure_hubs WHERE tour_id BETWEEN 321 AND 620;


DELETE FROM tour_schedules WHERE tour_id BETWEEN 321 AND 620;


